try:
    from botocore.exceptions import ClientError
except Exception:
    ClientError = Exception

app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots")
BASE_URL = os.getenv("BASE_URL", "")
SCREENSHOT_WIDTH = int(os.getenv("SCREENSHOT_WIDTH", "1280"))
SCREENSHOT_HEIGHT = int(os.getenv("SCREENSHOT_HEIGHT", "720"))
THUMBNAIL_WIDTH = int(os.getenv("THUMBNAIL_WIDTH", "320"))
THUMBNAIL_HEIGHT = int(os.getenv("THUMBNAIL_HEIGHT", "180"))
PAGE_LOAD_TIMEOUT = int(os.getenv("PAGE_LOAD_TIMEOUT", "20"))
WAIT_AFTER_LOAD = float(os.getenv("WAIT_AFTER_LOAD", "2.0"))
USE_PHANTOMJS = os.getenv("USE_PHANTOMJS", "0") == "1"
CACHE_TTL_SECONDS = int(os.getenv("CACHE_TTL_SECONDS", "2592000"))
ALLOW_PRIVATE_NETWORK = os.getenv("ALLOW_PRIVATE_NETWORK", "0") == "1"
MAX_URL_LENGTH = int(os.getenv("MAX_URL_LENGTH", "2048"))

s3 = boto3.client("s3", region_name=AWS_REGION)
_lock = threading.Lock()


def is_valid_url(url):
    if not url or len(url) > MAX_URL_LENGTH:
        return False
    try:
        parsed = urlparse(url)
        if parsed.scheme not in ("http", "https"):
            return False
        if not parsed.netloc:
            return False
        if re.search(r"[\s<>\"']", url):
            return False
        return True
    except Exception:
        return False


def is_private_host(hostname):
    if not hostname:
        return True
    h = hostname.lower()
    private_hosts = ("localhost", "127.", "10.", "192.168.", "169.254.", "0.", "::1")
    if h == "localhost" or h.endswith(".local"):
        return True
    return any(h.startswith(prefix) for prefix in private_hosts)


def safe_key_for_url(url):
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{digest[:2]}/{digest}.jpg"


def s3_object_exists(key):
    try:
        s3.head_object(Bucket=S3_BUCKET, Key=key)
        return True
    except ClientError:
        return False
    except Exception:
        return False


def s3_get_object_url(key):
    if BASE_URL:
        return f"{BASE_URL.rstrip('/')}/{key.lstrip('/')}"
    try:
        return s3.generate_presigned_url(
            "get_object",
            Params={"Bucket": S3_BUCKET, "Key": key},
            ExpiresIn=CACHE_TTL_SECONDS,
        )
    except Exception:
        return ""


def upload_to_s3(key, content, content_type="image/jpeg", metadata=None):
    extra = {"ContentType": content_type, "CacheControl": f"public, max-age={CACHE_TTL_SECONDS}"}
    if metadata:
        extra["Metadata"] = metadata
    s3.put_object(Bucket=S3_BUCKET, Key=key, Body=content, **extra)


def make_driver():
    if USE_PHANTOMJS:
        try:
            from selenium import webdriver as _webdriver
            driver = _webdriver.PhantomJS()
            driver.set_window_size(SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT)
            driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
            return driver
        except Exception:
            pass

    options = ChromeOptions()
    options.add_argument("--headless=new")
    options.add_argument(f"--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--disable-gpu")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--force-device-scale-factor=1")
    options.add_argument("--disable-software-rasterizer")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.add_argument("--disable-default-apps")
    options.add_argument("--disable-popup-blocking")
    if not ALLOW_PRIVATE_NETWORK:
        options.add_argument("--host-resolver-rules=MAP localhost 127.0.0.1")
    driver = webdriver.Chrome(options=options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    return driver


def capture_screenshot(url):
    driver = make_driver()
    try:
        driver.get(url)
        time.sleep(WAIT_AFTER_LOAD)
        try:
            WebDriverWait(driver, 5).until(
                EC.presence_of_element_located((By.TAG_NAME, "body"))
            )
        except Exception:
            pass

        png = driver.get_screenshot_as_png()
        img = Image.open(io.BytesIO(png)).convert("RGB")
        img.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.Resampling.LANCZOS)

        out = io.BytesIO()
        img.save(out, format="JPEG", quality=85, optimize=True)
        out.seek(0)
        return out.read()
    finally:
        try:
            driver.quit()
        except Exception:
            pass


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


@app.route("/screenshot", methods=["POST"])
def screenshot():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET is not configured"}), 500

    data = request.get_json(silent=True) or request.form.to_dict() or {}
    url = data.get("url", "").strip()
    if not is_valid_url(url):
        return jsonify({"error": "invalid url"}), 400

    hostname = urlparse(url).hostname or ""
    if not ALLOW_PRIVATE_NETWORK and is_private_host(hostname):
        return jsonify({"error": "private hosts are not allowed"}), 400

    key = safe_key_for_url(url)

    if s3_object_exists(key):
        return jsonify({"url": url, "key": key, "image_url": s3_get_object_url(key), "cached": True})

    with _lock:
        if s3_object_exists(key):
            return jsonify({"url": url, "key": key, "image_url": s3_get_object_url(key), "cached": True})
        try:
            content = capture_screenshot(url)
            upload_to_s3(
                key,
                content,
                content_type="image/jpeg",
                metadata={"source_url": url},
            )
            return jsonify({"url": url, "key": key, "image_url": s3_get_object_url(key), "cached": False})
        except Exception as e:
            return jsonify({"error": "capture failed", "detail": str(e)}), 500


@app.route("/screenshot", methods=["GET"])
def screenshot_get():
    url = request.args.get("url", "").strip()
    if not url:
        return jsonify({"error": "missing url"}), 400
    if not is_valid_url(url):
        return jsonify({"error": "invalid url"}), 400

    hostname = urlparse(url).hostname or ""
    if not ALLOW_PRIVATE_NETWORK and is_private_host(hostname):
        return jsonify({"error": "private hosts are not allowed"}), 400

    key = safe_key_for_url(url)
    if not s3_object_exists(key):
        try:
            content = capture_screenshot(url)
            upload_to_s3(
                key,
                content,
                content_type="image/jpeg",
                metadata={"source_url": url},
            )
        except Exception as e:
            return jsonify({"error": "capture failed", "detail": str(e)}), 500

    image_url = s3_get_object_url(key)
    if request.args.get("redirect", "0") == "1" and image_url:
        return jsonify({"url": url, "key": key, "image_url": image_url, "cached": True})
    return jsonify({"url": url, "key": key, "image_url": image_url, "cached": True})


@app.route("/preview", methods=["GET"])
def preview():
    url = request.args.get("url", "").strip()
    if not url:
        return jsonify({"error": "missing url"}), 400
    if not is_valid_url(url):
        return jsonify({"error": "invalid url"}), 400

    key = safe_key_for_url(url)
    if not s3_object_exists(key):
        try:
            content = capture_screenshot(url)
            upload_to_s3(
                key,
                content,
                content_type="image/jpeg",
                metadata={"source_url": url},
            )
        except Exception as e:
            return jsonify({"error": "capture failed", "detail": str(e)}), 500

    try:
        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        return send_file(io.BytesIO(obj["Body"].read()), mimetype="image/jpeg")
    except Exception:
        image_url = s3_get_object_url(key)
        if image_url:
            return jsonify({"image_url": image_url})
        return abort(404)


